# ---- new units ----

def tracker(group_state, frozen, now):
    """Main-text 'state of the group stage': one row per group. frozen is
    accepted for signature symmetry with the other units; the table shows
    only current values."""
    rows = []
    for g in group_state:
        top2 = g["rows"][:2]
        if g["played"]:
            standing = "; ".join(f"{r['team']} {r['Pts']}" for r in top2)
        else:
            standing = "--"
        leaders = sorted((r for r in g["rows"] if r["team"] in now),
                         key=lambda r: -now[r["team"]]["advance_KO"])[:2]
        qual = "; ".join(
            f"{r['team']} {_pct(now[r['team']]['advance_KO'])}" for r in leaders)
        rows.append(f"{g['group']} & {g['played']}/{g['total']} & {standing} & {qual} \\\\")
    return (
        "\\begin{table}[!t]\n  \\centering\n"
        "  \\caption{State of the group stage (live edition)}\\label{tab:tracker}\n"
        "  \\begin{footnotesize}\n"
        "  {\\begin{tabular*}{\\textwidth}{@{\\extracolsep{\\fill}} clll}\n"
        "    \\toprule\n"
        "    Group & Played & Standings (top two, real points) & Advance now (top two) \\\\\n"
        "    \\midrule\n    " + "\n    ".join(rows) + "\n"
        "    \\bottomrule\n  \\end{tabular*}}\n  \\end{footnotesize}\n\\end{table}")


def _record_from(team, group_exps, res_by_match, resolver):
    """Tally (W, D, L, Pts) for `team` across its group fixtures, taking played
    matches from `res_by_match` and unplayed ones from resolver(e) -> (hg, ag)."""
    w = d = l = pts = 0
    for e in group_exps:
        if team not in (e["home"], e["away"]):
            continue
        res = res_by_match.get(str(e["match"]))
        hg, ag = (tuple(res) if res else resolver(e))
        tf, ta = (hg, ag) if e["home"] == team else (ag, hg)
        if tf > ta:
            w += 1; pts += 3
        elif tf == ta:
            d += 1; pts += 1
        else:
            l += 1
    return w, d, l, pts


def group_box(g_state, results, expectations, frozen, now, now_b=None, track_b=None):
    """Appendix-A unified group table (spec 3.15) — ONE table per group, in the
    locked-matrix style: flag column headers (no rotated names), flag+name row
    labels, and a round-robin body whose played cells carry the bold actual score
    + check/cross and whose upcoming cells carry the predicted scoreline under
    Frozen/Track~A (one line, since both ride the June-10 ratings) and Track~B.
    Right panels give the Actual record (W/D/L/Pts/Qual\\%) and the projected
    final W/D/L/Pts under Frozen/Track~A and under Track~B. A remaining-fixtures
    H/D/A block sits below. track_b: {match: {'pick':[h,a],'hda':[h,d,a]}}."""
    grp = g_state["group"]
    teams = [r["team"] for r in g_state["rows"]]
    group_exps = [e for e in expectations if e.get("group") == grp]
    exps = {(e["home"], e["away"]): e for e in group_exps}
    res_by_match = results["group"]
    track_b = track_b or {}

    if not group_exps:
        return f"\\paragraph{{Group {grp} — live.}} Fixtures pending."

    def _sgn(x): return 1 if x > 0 else (-1 if x < 0 else 0)

    def _frozen_pick(e):                # Frozen and Track A share the submitted pick
        return tuple(e["pick"])

    def _track_b_pick(e):
        return tuple(track_b.get(e["match"], {}).get("pick", e["pick"]))

    # ---- one round-robin table, locked-matrix style -------------------------
    n = len(teams)
    col_spec = "cl" + "c" * n + "cccc"
    flag_hdr = " & ".join(_flag(t) for t in teams)
    panel_hdr = (
        "\\makecell{Actual \\\\ W/D/L/P} & "
        "\\makecell{Frozen \\\\ W/D/L/P/Q\\%} & "
        "\\makecell{Track~A \\\\ W/D/L/P/Q\\%} & "
        "\\makecell{Track~B \\\\ W/D/L/P/Q\\%}")
    header = f" & Team & {flag_hdr} & {panel_hdr} \\\\"

    body_rows = []
    for rank, home in enumerate(teams, 1):
        cells = []
        for away in teams:
            if home == away:
                cells.append("---")
                continue
            e = exps.get((home, away)) or exps.get((away, home))
            if e is None:
                cells.append("?")
                continue
            res = res_by_match.get(str(e["match"]))
            if res:                      # played: bold actual score + correct mark
                score = (f"{res[0]}--{res[1]}" if e["home"] == home
                         else f"{res[1]}--{res[0]}")
                pick = e["pick"]
                correct = _sgn(pick[0] - pick[1]) == _sgn(res[0] - res[1])
                icon = r"$\checkmark$" if correct else r"$\times$"
                cells.append(f"\\textbf{{{score}}}{icon}")
            else:                        # upcoming: Frozen=Track~A scoreline; Track~B if it differs
                fa, tb = _frozen_pick(e), _track_b_pick(e)
                if e["home"] == home:
                    f_s, b_s = f"{fa[0]}--{fa[1]}", f"{tb[0]}--{tb[1]}"
                else:
                    f_s, b_s = f"{fa[1]}--{fa[0]}", f"{tb[1]}--{tb[0]}"
                cells.append(f"F/A/B:{f_s}" if f_s == b_s
                             else f"F/A:{f_s}\\, B:{b_s}")

        # right panels — each W/D/L/Pts/Qual%: Actual (real record + current
        # qual), then projected final record under Frozen / Track A / Track B.
        # Records coincide for Frozen and Track A (shared June-10 ratings); the
        # qualification probabilities differ because Track A is result-conditioned.
        row = next((r for r in g_state["rows"] if r["team"] == home), {})
        aw, ad, al = row.get("W", 0), row.get("D", 0), row.get("L", 0)
        apts = row.get("Pts", 0)
        q_frozen = _pct(frozen[home]["advance_KO"]) if home in frozen else "--"
        q_a = _pct(now[home]["advance_KO"]) if home in now else "--"
        q_b = _pct(now_b[home]["advance_KO"]) if (now_b and home in now_b) else "--"
        actual = f"{aw}/{ad}/{al}/{apts}" if g_state["played"] else "--"
        fw, fd, fl, fp = _record_from(home, group_exps, res_by_match, _frozen_pick)
        bw, bd, bl, bp = _record_from(home, group_exps, res_by_match, _track_b_pick)
        body_rows.append(
            f"{rank} & {_flag(home)}~{_code3(home)} & " + " & ".join(cells)
            + f" & {actual} & {fw}/{fd}/{fl}/{fp}/{q_frozen}\\%"
            f" & {fw}/{fd}/{fl}/{fp}/{q_a}\\% & {bw}/{bd}/{bl}/{bp}/{q_b}\\% \\\\"
        )

    # ---- remaining-fixtures H/D/A block (below the matrix) -------------------
    state = (f"{g_state['played']} of {g_state['total']} played"
             if g_state["played"] else "fixtures pending")
    note = ("Teams are 3-letter codes. Round-robin body: row team's score against "
            "the column team. Played cells show the actual score in bold with "
            "$\\checkmark$/$\\times$ for the submitted result pick; upcoming cells "
            "give the predicted scoreline as F/A (Frozen=Track~A) and B (Track~B), "
            "collapsed to F/A/B when all agree. Right panels report W/D/L/Pts and "
            "qualification \\%: Actual is the real record so far; Frozen, Track~A, "
            "and Track~B give the projected final record (each remaining game "
            "resolved at that track's predicted scoreline) and that track's qual. "
            "Frozen and Track~A share the June~10 ratings, so their scoreline and "
            "projected record coincide; the two diverge only in the conditioned "
            "qualification \\%.")

    return (
        f"\\paragraph{{Group {grp} — live ({state}).}}\\leavevmode\\par\n"
        "\\noindent\\begin{threeparttable}\n"
        "{\\setlength{\\tabcolsep}{3pt}\\scriptsize\n"
        f"\\begin{{tabular*}}{{\\textwidth}}{{@{{\\extracolsep{{\\fill}}}}{col_spec}@{{}}}}\n"
        "\\toprule\n"
        f"{header}\n"
        "\\midrule\n"
        + "\n".join(body_rows) + "\n"
        "\\bottomrule\n"
        "\\end{tabular*}}\n"
        "\\begin{tablenotes}\\notesize\n"
        f"\\item \\textit{{Notes}}: {note}\n"
        "\\end{tablenotes}\n\\end{threeparttable}\n"
    )


def two_track_unit(two_track, learning, fig=False, info_snapshot=None, track_a=None,
                   champion_b=None, frozen_stages=None):
    """The live A-vs-B narrative. The champion-odds table is a strict subset of
    the headline Table~\\ref{tab:champ} (dropped); the learning-track Elo drift
    is folded into the divergence table (Table~\\ref{tab:live_divergence}); and
    the realized champion paths are the trajectory, Figure~\\ref{fig:trajectory}
    (the former standalone two-track path figure was redundant with it). fig /
    track_a / champion_b / frozen_stages / info_snapshot are accepted for caller
    compatibility but no longer rendered here."""
    if two_track is None:
        return ("\\textit{Two-track live results begin with the first match "
                "whose box score is collected.}")
    pend = (f" Stats pending for matches: "
            f"{', '.join(f'M{m:03d}' for m in learning['pending'])}."
            if learning["pending"] else "")
    n = len(learning["processed"])

    return (
        "\\subsection{The two tracks live: 2026 as it speaks}"
          "\\label{sec:twotracklive}\n"
          f"The pre-registered A-vs-B study of Appendix~D, running on the real "
          f"tournament: after each match the observed shot performance "
          f"($\\lambda_{{\\mathrm{{obs}}}}$, Appendix~D.2) updates Track~B's "
          f"ratings (k=50, locked), while Track~A re-conditions "
          f"on results alone. {n} match(es) processed so far.{pend}\n\n"
          "The three champion tracks are tabulated in "
          "Table~\\ref{tab:champ} (Frozen / Track~A / Track~B / Market) and their "
          "realized paths are Figure~\\ref{fig:trajectory}; the learning-track "
          "Elo drift that distinguishes Track~B is folded into the divergence "
          "table, Table~\\ref{tab:live_divergence}.")


def _stats_release(match, match_stats, learning):
    s = match_stats.get(match)
    rec = next((r for r in learning["processed"] if r["match"] == match), None)
    if s is None:
        return ("\\textit{Box-score statistics for this match are pending; the "
                "performance analysis will appear in the next edition.}")
    def _row(label, key, fmt="{:.0f}"):
        return (f"{label} & " + fmt.format(s['home'][key]) + " & "
                + fmt.format(s['away'][key]) + " \\\\")
    lines = [_row("Shots", "total_shots"), _row("On target", "sot")]
    if (s["home"].get("possession") is not None
            and s["away"].get("possession") is not None):
        lines.append(_row("Possession (\\%)", "possession", "{:.0f}"))
    perf = ""
    if rec:
        perf = (f"\\\\[2pt] Performance vs.\\ expectation: "
                f"$\\lambda_{{\\mathrm{{obs}}}}$ = {rec['lam_obs']['home']:.2f} / "
                f"{rec['lam_obs']['away']:.2f} against "
                f"$\\lambda_{{\\mathrm{{exp}}}}$ = {rec['lam_exp']['home']:.2f} / "
                f"{rec['lam_exp']['away']:.2f} "
                f"({rec['lam_obs']['source']} signal); the learning track moves "
                f"{rec['home']} by {rec['drift_after'].get(rec['home'], 0):+.1f} and "
                f"{rec['away']} by {rec['drift_after'].get(rec['away'], 0):+.1f} Elo.")
    return ("\\begin{table}[!h]\\centering\n"
            "\\caption{Match statistics (live edition M\\liveEditionNum{})}\\label{tab:live_edition_snapshot}\n"
            "\\begin{footnotesize}\\begin{tabular}{lrr}\\toprule\n"
            f" & {s['home']['team']} & {s['away']['team']} \\\\\n\\midrule\n"
            + "\n".join(lines) + "\n\\bottomrule\\end{tabular}\\end{footnotesize}"
            + perf
            + "\n\\end{table}")


def _pad2(v):
    """Two-digit zero-padded integer for column alignment (7 -> 07, 16 -> 16).
    Shots and shots-on-target are whole counts. '--' passes through unchanged."""
    return f"{int(round(v)):02d}" if isinstance(v, (int, float)) else str(v)


def _ppct(x):
    """Zero-padded percent, integer part to two digits (0.061 -> 06.1, 0.672 ->
    67.2), so the H/D/A triples line up under one another."""
    return f"{100 * x:04.1f}"


def _cumulative_stats_table(entries, match_stats, expectations, issue_order=None,
                            implications=None):
    """Table 7: a two-panel table. Panel A is one row per played match, grows
    with each edition, ordered by true issue order (GXXX, the order the model
    conditioned on results) not by schedule number (MXXX); the Game column shows
    both. Panel B (when ``implications`` is given) folds in the upcoming-fixture
    implications that used to be a separate unnumbered table.
    Panel A columns: Game | Shots H–A | On target H–A | Poss H–A | Frozen H/D/A |
    Track B H/D/A. Track B H/D/A is stored in entry['pre']['probs_HDA_b'] at
    documentation time (pre-match learn_ratings); '--' before that feature."""
    rows = []
    exp_by_match = {e["match"]: e for e in expectations}
    if issue_order:
        gidx = {m: i + 1 for i, m in enumerate(issue_order)}   # 1-based G index
        ordered = sorted(entries, key=lambda e: gidx.get(e["match"], 10 ** 6))
    else:
        gidx = {}
        ordered = list(entries)
    for pos, e in enumerate(ordered, start=1):
        m = e["match"]
        s = match_stats.get(m)
        if s is None:
            continue
        g = gidx.get(m, pos)            # true issue position (matches Table 8)
        sh = _pad2(s["home"].get("total_shots", "--"))
        sa = _pad2(s["away"].get("total_shots", "--"))
        oh = _pad2(s["home"].get("sot", "--"))
        oa = _pad2(s["away"].get("sot", "--"))
        ph = s["home"].get("possession")
        pa = s["away"].get("possession")
        poss = f"{ph:02.0f}--{pa:02.0f}" if ph is not None and pa is not None else "--"
        exp = exp_by_match.get(m)
        hda = "/".join(_ppct(p) for p in exp["probs_HDA"]) if exp else "--"
        hda_b_raw = e.get("pre", {}).get("probs_HDA_b")
        hda_b = "/".join(_ppct(p) for p in hda_b_raw) if hda_b_raw else "--"
        rows.append(
            f"{g} & {m} & {ic.fixture_tag(e['fixture'])} & {sh}--{sa} & "
            f"{oh}--{oa} & {poss} & {hda} & {hda_b} \\\\")
    if not rows and not implications:
        return r"\textit{Match statistics pending.}"
    # One aligned tabular so Panel B's last two columns line up beneath Panel A's,
    # with shared G / M columns. Columns: G | M | Fixture | Shots | On target |
    # Poss% | Frozen H/D/A | Track B H/D/A.
    col_spec = "rrlccccc"
    header = ("G & M & Fixture & Shots (H--A) & On target (H--A) & "
              "Poss\\% (H--A) & Frozen H/D/A & Track~B H/D/A \\\\")
    body = ["\\multicolumn{8}{@{}l}{\\itshape Panel A. Cumulative match statistics "
            "(played matches, in issue order).} \\\\", "\\midrule", header, "\\midrule"]
    body += rows if rows else [
        "\\multicolumn{8}{@{}l}{\\itshape Match statistics pending.} \\\\"]
    if implications:
        body += ["\\midrule",
                 "\\multicolumn{8}{@{}l}{\\itshape Panel B. Implications for upcoming "
                 "fixtures --- Frozen = pre-kickoff baseline; Track~B = live Elo + "
                 "bookmaker odds.} \\\\", "\\midrule"]
        for i in implications:
            body.append(
                f"-- & {i['match']} & {ic.fixture_tag(i['fixture'])} & -- & -- & -- & "
                f"{'/'.join(_ppct(p) for p in i['lock_HDA'])} & "
                f"{'/'.join(_ppct(p) for p in i['learn_HDA'])} \\\\")
    caption = ("Cumulative match statistics and upcoming-fixture implications"
               if implications else "Cumulative match statistics")
    return (
        "\\begin{table}[!h]\\centering\n"
        f"\\caption{{{caption} (live edition M\\liveEditionNum{{}})}}"
        "\\label{tab:live_match_stats}\n"
        "\\begin{footnotesize}\n"
        f"\\begin{{tabular}}{{{col_spec}}}\\toprule\n"
        + "\n".join(body) + "\n\\bottomrule\\end{tabular}\n"
        "\\end{footnotesize}\n\\end{table}"
    )


def revision_report(ctx):
    """The central-bank release: data release, forecast revision (the marginal
    effect of this match's result), implications, vintages. Driver contract:
    ctx['prev_now'] is the forecast conditioned on this edition's matches except
    the one just released, and ctx['match'] equals the latest entry's match."""
    import vintages as vin
    m = ctx["match"]
    latest = max(ctx["entries"], key=lambda e: e["match"])
    prev, now = ctx["prev_now"], ctx["now"]
    frozen = ctx.get("frozen", {})
    champion_b = ctx.get("champion_b", {})

    # Delta vs previous edition (the "news" of this edition)
    deltas_vs_prev = []
    for t in sorted(now, key=lambda t: -now[t]["champion"])[:8]:
        if t in prev:
            d = 100 * (now[t]["champion"] - prev[t]["champion"])
            if abs(d) >= 0.05:
                deltas_vs_prev.append(f"{t} {d:+.1f}")
    delta_line = ("; ".join(deltas_vs_prev) if deltas_vs_prev
                  else "no contender moved by 0.1 pp or more")

    # Track A vs Frozen: cumulative shift from baseline
    deltas_af = []
    for t in sorted(now, key=lambda t: -now[t]["champion"])[:8]:
        if t in frozen:
            d = 100 * (now[t]["champion"] - frozen[t].get("champion", 0.0))
            if abs(d) >= 0.05:
                deltas_af.append(f"{t} {d:+.1f}")
    delta_af = ("; ".join(deltas_af) if deltas_af
                else "no contender has moved 0.1 pp or more from baseline")

    # Track B vs Track A: gap between the two tracks
    b_vs_a_line = ""
    if champion_b:
        deltas_ba = []
        for t in sorted(now, key=lambda t: -now[t]["champion"])[:8]:
            if t in champion_b:
                d = 100 * (champion_b[t] - now[t]["champion"])
                if abs(d) >= 0.05:
                    deltas_ba.append(f"{t} {d:+.1f}")
        delta_ba = ("; ".join(deltas_ba) if deltas_ba
                    else "no contender diverged by 0.1 pp or more between tracks")
        b_vs_a_line = f"\n\nTrack~B vs.\\ Track~A: {delta_ba}."
    return (
        f"\\subsection{{Revision report: edition M{m:03d}}}\\label{{sec:revreport}}\n"
        f"\\paragraph{{The data release.}} Match {latest['match']}, "
        f"{latest['fixture']}: predicted {latest['pre']['pick'][0]}--"
        f"{latest['pre']['pick'][1]}, actual {latest['result'][0]}--"
        f"{latest['result'][1]}; {latest['post']['points']} of 3 points, Brier "
        f"{latest['post']['brier']:.3f}, {latest['post']['info_bits']:.3f} bits.\n\n"
        + _cumulative_stats_table(
            ctx["entries"], ctx["match_stats"],
            ctx.get("expectations", []),
            issue_order=ctx.get("issue_order"),
            implications=ctx.get("implications")) + "\n\n"
        f"\\paragraph{{Forecast revision: marginal effect of this result.}} "
        f"Champion-probability movement attributable to match {latest['match']}'s "
        f"result (this edition vs.\\ the same forecast without it): {delta_line}.\n\n"
        f"Track~A vs.\\ Frozen: {delta_af}.{b_vs_a_line}\n\n"
        "\\paragraph{Forecast vintages.} Track~B champion probabilities, one row "
        "per issued edition, in issue order; the locked M000 (Frozen baseline) "
        "row never changes.\n\n"
        + vin.latex_table(ctx["vintages_rows"], issue_order=ctx.get("issue_order")))


