def _slot_status(frozen_pct, track_b_pct):
    drop = frozen_pct - track_b_pct
    if drop < 5:
        return "\\checkmark"
    if drop <= 20:
        return "$\\triangle$"
    return "$\\times$"


def _slot_risk_table(frozen, now, now_b):
    """R32 slot-risk table: does each pre-registered pick still advance, under
    Frozen / Track A / Track B?  Group-stage companion to the bracket figures."""
    has_b = bool(now_b)
    rows = []
    for home, away, mn in _R32_PAIRS:
        for team in (home, away):
            fr = frozen.get(team, {}).get("advance_KO", 0.0)
            ta = now.get(team, frozen.get(team, {})).get("advance_KO", fr)
            tb = now_b.get(team, {}).get("advance_KO", float("nan")) if has_b else float("nan")
            fr_p, ta_p = round(100 * fr, 1), round(100 * ta, 1)
            tb_str = f"{100 * tb:.1f}" if tb == tb else "--"
            status = _slot_status(fr_p, 100 * tb if tb == tb else fr_p) if has_b else ""
            b_col = f" & {tb_str} & {status}" if has_b else ""
            rows.append(f"{team} advance & M{mn} & {fr_p} & {ta_p}{b_col} \\\\")
    if has_b:
        col_spec = "llrrrl"
        hdr = "KO Pick & Slot & Frozen~\\% & Track~A~\\% & Track~B~\\% & Status \\\\"
        note = ("Status: \\checkmark{} = Track~B within 5 pp of Frozen; "
                "$\\triangle$ = 5--20 pp drop; $\\times$ = pick reversed ($>$20 pp).")
    else:
        col_spec, hdr, note = "llrr", "KO Pick & Slot & Frozen~\\% & Track~A~\\% \\\\", ""
    notes_block = (f"\n  \\begin{{tablenotes}}\\notesize\n  \\item \\textit{{Notes:}} "
                   f"{note}\n  \\end{{tablenotes}}" if note else "")
    return (
        "\\begin{table}[!t]\n  \\centering\n"
        "  \\caption{R32 slot risk: probability each pre-registered pick "
        "advances from the group stage (live edition M\\liveEditionNum{})"
        "}\\label{tab:live_slot_risk}\n"
        f"  \\begin{{footnotesize}}\\begin{{threeparttable}}\n"
        f"  \\begin{{tabular}}{{{col_spec}}}\n"
        f"  \\toprule\n  {hdr}\n  \\midrule\n  " + "\n  ".join(rows) + "\n"
        "  \\bottomrule\\end{tabular}"
        + notes_block +
        "\n  \\end{threeparttable}\\end{footnotesize}\n\\end{table}")


def bracket_live_unit(ctx):
    """The knockout bracket, three ways (spec 3.20): the submitted Frozen bracket
    is the locked TikZ Figure~\\ref{fig:bracket}; the live Track A and Track B
    brackets re-value that same bracket by champion probability and grey out
    teams eliminated by confirmed results. During the group stage a slot-risk
    table also tracks whether each R32 pick is still advancing."""
    ko_results = ctx.get("results", {}).get("ko", {})
    frozen, now = ctx.get("frozen", {}), ctx.get("now", {})
    now_b = ctx.get("now_b", {})

    discussion = (
        "\\paragraph{The bracket, three ways.} The submitted knockout entry is "
        "the Frozen bracket of Figure~\\ref{fig:bracket}, which never changes. "
        "The two live brackets below re-value that same submitted bracket by each "
        "team's champion probability under Track~A (result-conditioning on the "
        "June~10 ratings) and Track~B (live Elo and bookmaker odds), and once the "
        "knockout rounds begin they shade out teams eliminated by confirmed "
        "results. Read together with the locked bracket, they show how far the "
        "live forecast has drifted from the path the entry committed to; the "
        "slot-risk table below tracks the same question one pick at a time while "
        "the group stage is still running.\n\n")

    slot_table = ("" if ko_results
                  else _slot_risk_table(frozen, now, now_b) + "\n\n")

    figs = (
        "\\begin{figure}[!t]\n"
        "  \\caption{The submitted bracket re-valued by champion probability "
        "under Track~A (top) and Track~B (bottom) at live edition "
        "M\\liveEditionNum{}; the gold box is each track's most likely champion "
        "and greyed boxes are teams eliminated by confirmed results. The locked "
        "submitted bracket is Figure~\\ref{fig:bracket}.}\\label{fig:live_bracket}\n"
        "  {\\centering\\includegraphics[width=0.92\\textwidth]"
        "{figs/fig_live_bracket_a.pdf}\\par\\smallskip\n"
        "  \\includegraphics[width=0.92\\textwidth]"
        "{figs/fig_live_bracket_b.pdf}\\par}\n"
        "\\end{figure}")

    ml_figs = (
        "\\begin{figure}[!t]\n"
        "  \\caption{The \\emph{most-likely} bracket: the same submitted layout, "
        "but each Round-of-32 slot is re-filled with the team most likely to "
        "occupy it (rather than the locked pick) under Track~A (top) and Track~B "
        "(bottom) at live edition M\\liveEditionNum{}. Round-of-32 boxes show the "
        "probability that team reaches the slot; rounds past the Round of 32 trace "
        "the Elo most-likely path with boxes showing champion probability, and "
        "upgrade to exact per-slot occupancy once the knockout draw is realised. "
        "Read against Figure~\\ref{fig:live_bracket}, it shows where the live "
        "forecast would re-cast the bracket the entry locked in.}"
        "\\label{fig:mostlikely_bracket}\n"
        "  {\\centering\\includegraphics[width=0.92\\textwidth]"
        "{figs/fig_mostlikely_bracket_a.pdf}\\par\\smallskip\n"
        "  \\includegraphics[width=0.92\\textwidth]"
        "{figs/fig_mostlikely_bracket_b.pdf}\\par}\n"
        "\\end{figure}")

    return discussion + slot_table + figs + "\n\n" + ml_figs


def survival_colcomp_unit(ctx):
    """Appendix B.live: side-by-side Frozen / Track A / Track B survival probabilities.
    Shows F/A/B when ctx['now_b'] is available, F/A otherwise."""
    frozen = ctx["frozen"]
    now = ctx["now"]
    now_b = ctx.get("now_b", {})
    has_b = bool(now_b)
    teams = sorted(now, key=lambda t: (-now[t]["champion"], -now[t]["advance_KO"]))
    stages = ["advance_KO", "R16", "QF", "SF", "final", "champion"]
    headers = "Team & KO & R16 & QF & SF & Final & Champion \\\\"

    def triple(t, stage):
        f = frozen.get(t, {}).get(stage, 0.0)
        a = now[t].get(stage, 0.0)
        delta = abs(a - f)            # zero-padded (07.0) so the F/A/B cells align
        a_str = f"\\textbf{{{_ppct(a)}}}" if delta > 3.0 else _ppct(a)
        if has_b and t in now_b:
            b = now_b[t].get(stage, 0.0)
            return f"{_ppct(f)}/{a_str}/{_ppct(b)}"
        return f"{_ppct(f)}/{a_str}"

    rows = [
        t + " & " + " & ".join(triple(t, s) for s in stages) + " \\\\"
        for t in teams if t in frozen
    ]
    if has_b:
        note = "Each cell shows F/A/B = Frozen\\%{}/Track~A\\%/Track~B\\%; bold Track~A when $|\\Delta| > 3$ pp."
        title = "Frozen / Track~A / Track~B stage probabilities, all 48 teams"
    else:
        note = "Each cell shows Frozen\\%{}~/{}Track~A\\%; bold Track~A when $|\\Delta| > 3$ pp."
        title = "Frozen vs.\\ Track~A stage probabilities, all 48 teams"
    return (
        "\\section*{Appendix B\\quad The same distribution, "
        "all three tracks side by side}\\label{app:survlive}\n"
        + note + "\n\n"
        "\\begin{scriptsize}\n\\begin{longtable}{lrrrrrr}\n"
        "\\caption{" + title + " "
        "(live edition M\\liveEditionNum{})}\\label{tab:live_survcomp}\\\\\n"
        "\\toprule\n" + headers + "\n\\midrule\n"
        "\\endfirsthead\n"
        "\\toprule\n" + headers + "\n\\midrule\n"
        "\\endhead\n"
        + "\n".join(rows) + "\n"
        "\\bottomrule\n\\end{longtable}\n\\end{scriptsize}"
    )


